#include "interface.h"
#include <cuda_runtime.h>
#include <thrust/device_ptr.h>
#include <thrust/sort.h>
#include <thrust/execution_policy.h>

void sort_vec_i32(const int* input, int* output, int n, int iters) {
  if (n <= 0 || iters <= 0) return;
  cudaStream_t stream = 0; // default stream

  for (int iter = 0; iter < iters; ++iter) {
    if (output != input) {
      cudaMemcpyAsync(output, input, static_cast<size_t>(n) * sizeof(int), cudaMemcpyDeviceToDevice, stream);
    }
    thrust::device_ptr<int> begin = thrust::device_pointer_cast(output);
    thrust::sort(thrust::cuda::par.on(stream), begin, begin + n);
  }
  // Ensure all work is completed before returning
  cudaStreamSynchronize(stream);
}
